import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import './StudentDashboard.css';

export default function StudentDashboard() {
  const [complaints, setComplaints] = useState([]);
  const [form, setForm] = useState({ category: '', description: '', priority: 'medium' });
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const user = JSON.parse(localStorage.getItem('user'));

  useEffect(() => {
    if (!token) navigate('/login');
    fetchComplaints();
  }, []);

  const fetchComplaints = async () => {
    try {
      const res = await axios.get('/api/complaints/my', { headers: { 'x-auth-token': token } });
      setComplaints(res.data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleChange = e => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async e => {
    e.preventDefault();
    setSubmitting(true);
    setError('');
    try {
      await axios.post('/api/complaints', form, { headers: { 'x-auth-token': token } });
      setSuccess('Complaint submitted');
      setForm({ category: '', description: '', priority: 'medium' });
      fetchComplaints();
      setTimeout(() => setSuccess(''), 3000);
    } catch (err) {
      setError('Failed to submit');
    } finally {
      setSubmitting(false);
    }
  };

  const logout = () => { localStorage.clear(); navigate('/login'); };

  const formatDate = d => new Date(d).toLocaleDateString();

  if (loading) return <div className="loading">Loading...</div>;

  return (
    <div className="student-container">
      <nav className="student-nav">
        <div className="nav-content">
          <div className="nav-brand"><h1>Hostel<span>Hub</span></h1><p>Student</p></div>
          <div className="nav-user">
            <span>{user?.name}</span>
            <button onClick={logout} className="logout-btn">Logout</button>
          </div>
        </div>
      </nav>

      <div className="student-content">
        <div className="complaint-form-section">
          <h2>New Complaint</h2>
          {error && <div className="error-message">{error}</div>}
          {success && <div className="success-message">{success}</div>}
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>Category</label>
              <select name="category" value={form.category} onChange={handleChange} required>
                <option value="">Select</option>
                <option value="plumbing">Plumbing</option>
                <option value="electrical">Electrical</option>
                <option value="carpentry">Carpentry</option>
                <option value="cleaning">Cleaning</option>
                <option value="other">Other</option>
              </select>
            </div>
            <div className="form-group">
              <label>Description</label>
              <textarea name="description" rows="4" value={form.description} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label>Priority</label>
              <select name="priority" value={form.priority} onChange={handleChange}>
                <option value="low">Low</option>
                <option value="medium">Medium</option>
                <option value="high">High</option>
              </select>
            </div>
            <button type="submit" disabled={submitting}>{submitting ? 'Submitting...' : 'Submit'}</button>
          </form>
        </div>

        <div className="complaints-list-section">
          <h2>My Complaints</h2>
          {complaints.length === 0 ? <p>No complaints</p> : complaints.map(c => (
            <div key={c._id} className="complaint-card">
              <h3>{c.category}</h3>
              <p>{c.description}</p>
              <div className="complaint-footer">
                <span className={`priority-${c.priority}`}>{c.priority}</span>
                <span className={`status-${c.status.replace('-','')}`}>{c.status}</span>
                <span>{formatDate(c.createdAt)}</span>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
